import { ZuploContext, ZuploRequest } from "@zuplo/runtime";

// In-memory customer dataset
const customers: Record<string, { name: string; email: string; plan: string; revenue: number; status: string }> = {
  "cust-001": {
    name: "Acme Corp",
    email: "billing@acme.com",
    plan: "Enterprise",
    revenue: 125000,
    status: "Active",
  },
  "cust-002": {
    name: "Globex Inc",
    email: "finance@globex.io",
    plan: "Professional",
    revenue: 48000,
    status: "Active",
  },
  "cust-003": {
    name: "Initech LLC",
    email: "accounts@initech.com",
    plan: "Starter",
    revenue: 12000,
    status: "Churned",
  },
};

export default async function (request: ZuploRequest, context: ZuploContext) {
  const body = await request.json();

  const customerId = body?.customerId;

  if (!customerId || typeof customerId !== "string") {
    return new Response(
      JSON.stringify({
        error: "Missing or invalid 'customerId' parameter",
      }),
      {
        status: 400,
        headers: { "Content-Type": "application/json" },
      }
    );
  }

  const customer = customers[customerId];

  if (!customer) {
    return new Response(
      JSON.stringify({
        error: `Customer '${customerId}' not found`,
      }),
      {
        status: 404,
        headers: { "Content-Type": "application/json" },
      }
    );
  }

  const summary = `Customer Summary for ${customerId}:\n- Name: ${customer.name}\n- Email: ${customer.email}\n- Plan: ${customer.plan}\n- Revenue: $${customer.revenue.toLocaleString()}\n- Status: ${customer.status}`;

  return new Response(
    JSON.stringify({
      customerId,
      name: customer.name,
      email: customer.email,
      plan: customer.plan,
      revenue: customer.revenue,
      status: customer.status,
      summary,
    }),
    {
      status: 200,
      headers: { "Content-Type": "application/json" },
    }
  );
}

{
  "openapi": "3.1.0",
  "info": {
    "version": "1.0.0",
    "title": "MCP Customer API",
    "description": "An API gateway that exposes customer data as an MCP tool for AI agents."
  },
  "paths": {
    "/mcp": {
      "post": {
        "summary": "MCP Server Endpoint",
        "description": "Handles MCP JSON-RPC requests for tool discovery and invocation.",
        "operationId": "mcp-server",
        "x-zuplo-route": {
          "corsPolicy": "none",
          "handler": {
            "export": "mcpServerHandler",
            "module": "$import(@zuplo/runtime)",
            "options": {
              "name": "customer-mcp-server",
              "version": "1.0.0",
              "operations": [
                {
                  "file": "./config/routes.oas.json",
                  "id": "get-customer-summary"
                }
              ]
            }
          }
        },
        "responses": {
          "200": {
            "description": "MCP JSON-RPC response"
          }
        }
      }
    },
    "/customers/summary": {
      "post": {
        "summary": "Get Customer Summary",
        "description": "Retrieves a summary of a customer by their customer ID. This tool is exposed as an MCP tool.",
        "operationId": "get-customer-summary",
        "x-zuplo-route": {
          "corsPolicy": "none",
          "mcp": {
            "type": "tool"
          },
          "handler": {
            "export": "default",
            "module": "$import(./modules/get-customer-summary.ts)"
          }
        },
        "requestBody": {
          "required": true,
          "content": {
            "application/json": {
              "schema": {
                "type": "object",
                "properties": {
                  "customerId": {
                    "type": "string",
                    "description": "The unique identifier of the customer"
                  }
                },
                "required": ["customerId"]
              }
            }
          }
        },
        "responses": {
          "200": {
            "description": "Customer summary",
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "properties": {
                    "customerId": { "type": "string" },
                    "name": { "type": "string" },
                    "email": { "type": "string" },
                    "plan": { "type": "string" },
                    "revenue": { "type": "number" },
                    "status": { "type": "string" },
                    "summary": { "type": "string" }
                  }
                }
              }
            }
          },
          "400": {
            "description": "Invalid request"
          },
          "404": {
            "description": "Customer not found"
          }
        }
      }
    }
  }
