I,WAA0C,CAAC;IAE/C,IAAI,SAAS,EAAE,CAAC;QACd,MAAM,aAAa,GAAG,OAAO,CAAC,QAAQ,KAAK,OAAO,CAAC,CAAC,CAAC,SAAS,CAAC,CAAC,CAAC,KAAK,CAAC;QACvE,WAAW,GAAG,KAAK,CACjB,aAAa,EACb,CAAC,QAAQ,EAAE,KAAK,EAAE,SAAS,EAAE,QAAQ,EAAE,MAAM,CAAC,QAAQ,CAAC,CAAC,EACxD;YACE,GAAG,EAAE,aAAa;YAClB,GAAG,EAAE;gBAEH,GAAG,OAAO,CAAC,GAAG;gBAKd,WAAW,EAAE,GAAG;gBAEhB,gBAAgB,EAAE,oBAAoB,OAAO,EAAE;aAChD;SACF,CACF,CAAC;QACF,MAAM,mBAAmB,GAAG,uBAAuB,CAAC;YAClD,IAAI,EAAE,MAAM;YACZ,KAAK,EAAE,KAAK,CAAC,OAAO;SACrB,CAAC,CAAC;QACH,MAAM,mBAAmB,GAAG,uBAAuB,CAAC;YAClD,IAAI,EAAE,MAAM;YACZ,KAAK,EAAE,KAAK,CAAC,OAAO;SACrB,CAAC,CAAC;QACH,WAAW,CAAC,MAAM,EAAE,IAAI,CAAC,mBAAmB,CAAC,CAAC,IAAI,CAAC,OAAO,CAAC,MAAM,CAAC,CAAC;QACnE,WAAW,CAAC,MAAM,EAAE,IAAI,CAAC,mBAAmB,CAAC,CAAC,IAAI,CAAC,OAAO,CAAC,MAAM,CAAC,CAAC;IACrE,CAAC;IAED,yBAAyB,CAAC,iCAAiC,CAAC,CAAC;IAC7D,yBAAyB,CAAC,gBAAgB,CAAC,CAAC;IAC5C,yBAAyB,CAAC,EAAE,CAAC,CAAC;IAC9B,yBAAyB,CAAC,sCAAsC,OAAO,EAAE,CAAC,CAAC;IAC3E,IAAI,IAAI,CAAC,cAAc,CAAC,EAAE,CAAC;QACzB,yBAAyB,CACvB,uCAAuC,IAAI,CAAC,UAAU,EAAE,CACzD,CAAC;IACJ,CAAC;IACD,IAAI,SAAS,EAAE,CAAC;QACd,yBAAyB,CAAC,oCAAoC,QAAQ,EAAE,CAAC,CAAC;IAC5E,CAAC;IACD,IAAI,cAAc,CAAC,MAAM,GAAG,CAAC,EAAE,CAAC;QAC9B,yBAAyB,CACvB,iCAAiC,cAAc,CAAC,IAAI,CAAC,WAAW,CAAC,EAAE,CACpE,CAAC;IACJ,CAAC;IACD,yBAAyB,CAAC,EAAE,CAAC,CAAC;IAC9B,yBAAyB,CAAC,EAAE,CAAC,CAAC;IAE9B,OAAO,IAAI,OAAO,CAAO,CAAC,OAAO,EAAE,EAAE;QACnC,KAAK,UAAU,IAAI;YACjB,OAAO,CAAC,GAAG,CAAC,SAAS,EAAE,IAAI,CAAC,CAAC;YAC7B,OAAO,CAAC,GAAG,CAAC,QAAQ,EAAE,IAAI,CAAC,CAAC;YAE5B,yBAAyB,CAAC,EAAE,CAAC,CAAC;YAC9B,yBAAyB,CAAC,sCAAsC,CAAC,CAAC;YAElE,IAAI,IAAI,CAAC,cAAc,CAAC,EAAE,CAAC;gBACzB,MAAM,MAAM,CAAC,KAAK,EAAE,CAAC;YACvB,CAAC;YACD,IAAI,WAAW,EAAE,CAAC;gBAChB,WAAW,CAAC,IAAI,CAAC,SAAS,CAAC,CAAC;YAC9B,CAAC;YAED,OAAO,EAAE,CAAC;QACZ,CAAC;QAGD,OAAO,CAAC,EAAE,CAAC,SAAS,EAAE,IAAI,CAAC,CAAC;QAC5B,OAAO,CAAC,EAAE,CAAC,QAAQ,EAAE,IAAI,CAAC,CAAC;QAG3B,IAAI,WAAW,EAAE,CAAC;YAChB,WAAW,CAAC,EAAE,CAAC,OAAO,EAAE,CAAC,IAAI,EAAE,MAAM,EAAE,EAAE;gBACvC,IAAI,MAAM,KAAK,SAAS,IAAI,MAAM,KAAK,QAAQ,EAAE,CAAC;oBAChD,OAAO;gBACT,CAAC;gBAED,IAAI,IAAI,KAAK,CAAC,EAAE,CAAC;oBACf,qBAAqB,CAAC,gCAAgC,IAAI,GAAG,CAAC,CAAC;gBACjE,CAAC;YACH,CAAC,CAAC,CAAC;YAEH,WAAW,CAAC,EAAE,CAAC,OAAO,EAAE,CAAC,GAAG,EAAE,EAAE;gBAC9B,qBAAqB,CAAC,gCAAgC,GAAG,CAAC,OAAO,EAAE,CAAC,CAAC;YACvE,CAAC,CAAC,CAAC;QACL,CAAC;IACH,CAAC,CAAC,CAAC;AACL,CAAC","sourcesContent":["import { randomUUID } from "node:crypto";
import { cpSync, existsSync, readFileSync } from "node:fs";
import { join, resolve } from "node:path";
import { fileURLToPath } from "node:url";
import { LocalEditorServer } from "@zuplo/editor";
import chalk from "chalk";
import dotenv from "dotenv";
import { ExecaChildProcess, execa } from "execa";
import { logger } from "../common/logger.js";
import {
  ConsoleOutput,
  printCriticalFailureToConsoleAndExit,
  printDiagnosticsToConsole,
  printWarningToConsole,
} from "../common/output.js";
import { isPortAvailable } from "../common/utils/ports.js";
import { createPrefixedTransform } from "../common/utils/prefixed-output.js";
import { createRuntimeStdioHandler } from "../common/worker-output.js";

export interface Arguments {
  dir: string;
  "start-editor": boolean;
  "start-docs": boolean;
  port: number;
  editorPort: number;
  docsPort: number;
  debugPort?: number;
  unsafelyIgnoreCertificateErrors?: boolean;
}

export async function dev(argv: Arguments) {
  const sourceDirectory = resolve(argv.dir);

  // When we build, we MIGHT need to use the @zuplo/runtime from the node_modules if the user
  // has installed our packages using https://www.npmjs.com/package/zuplo in a global directory

  // Try to copy the @zuplo/runtime locally
  const zuploRuntimePath = new URL(
    "../../node_modules/@zuplo/runtime",
    import.meta.url
  );
  if (existsSync(zuploRuntimePath)) {
    cpSync(
      zuploRuntimePath,
      join(sourceDirectory, "node_modules/@zuplo/runtime"),
      {
        recursive: true,
        dereference: true,
      }
    );
  }

  // Set GLOBAL_MODULE_LOCATION to the location of the CLIs node_modules
  // biome-ignore lint/style/noProcessEnv: Migrated from ESLint
  process.env.GLOBAL_MODULE_LOCATION = fileURLToPath(
    new URL("../../node_modules", import.meta.url)
  );

  const loadedEnvFiles: string[] = [];

  // Check if the user has a .env file
  const envFile = join(sourceDirectory, ".env");
  if (existsSync(envFile)) {
    loadedEnvFiles.push(".env");
  }

  // Check if the user has a .env.zuplo file
  let envZuplo: dotenv.DotenvParseOutput | undefined;
  const envZuploFile = join(sourceDirectory, ".env.zuplo");
  if (existsSync(envZuploFile)) {
    const contents = readFileSync(envZuploFile);
    envZuplo = dotenv.parse(contents);
    loadedEnvFiles.push(".env.zuplo");
  }

  // Set other variables using __ZUPLO_CONFIG as necessary
  // const config = {
  // };
  // process.env.__ZUPLO_CONFIG = btoa(JSON.stringify(config));
  // biome-ignore lint/style/noProcessEnv: Migrated from ESLint
  process.env.ZUPLO_IS_LOCAL_DEVELOPMENT = "true";

  // Use a dynamic import so that setting process.env has effect
  const core = await import("@zuplo/core/cli");

  const zupPort = argv.port;
  const zupEditorPort = argv.editorPort;
  const zupDebugPort = argv.debugPort;

  const isZupPortAvailable = await isPortAvailable("localhost", zupPort);
  if (!isZupPortAvailable) {
    await printCriticalFailureToConsoleAndExit(
      `Port ${zupPort} is already in use. Please specify a different port using --port.`
    );
  }

  const isZupEditorPortAvailable = await isPortAvailable(
    "localhost",
    zupEditorPort
  );
  if (!isZupEditorPortAvailable) {
    await printCriticalFailureToConsoleAndExit(
      `Port ${zupEditorPort} is already in use. Please specify a different port using --editor-port.`
    );
  }

  if (zupDebugPort) {
    const isZupDebugPortAvailable = await isPortAvailable(
      "localhost",
      zupDebugPort
    );
    if (!isZupDebugPortAvailable) {
      await printCriticalFailureToConsoleAndExit(
        `Port ${zupDebugPort} is already in use. Please specify a different port using --debug-port.`
      );
    }
  }

  const docsDirectory = join(sourceDirectory, "docs");
  const hasDocsDirectory = existsSync(docsDirectory);
  if (!hasDocsDirectory) {
    printWarningToConsole(
      `Warning: docs/ directory not found at ${docsDirectory}. Skipping docs server.`
    );
  }

  const startDocs = argv["start-docs"] && hasDocsDirectory;
  const docsPort = argv.docsPort;

  if (startDocs) {
    const isDocsPortAvailable = await isPortAvailable("localhost", docsPort);
    if (!isDocsPortAvailable) {
      await printCriticalFailureToConsoleAndExit(
        `Port ${docsPort} is already in use. Please specify a different port using --docs-port.`
      );
    }
  }

  const buildId = randomUUID();

  let firstLoad = true;

  const handleRuntimeStdio = createRuntimeStdioHandler({
    prefix: "gateway",
    prefixColor: chalk.cyan,
  });
  await core.startDevServer({
    buildId,
    output: new ConsoleOutput(),
    sourceDirectory,
    port: zupPort,
    debugPort: argv.debugPort,
    devPortalPort: startDocs ? docsPort : undefined,
    unsafelyIgnoreCertificateErrors: argv.unsafelyIgnoreCertificateErrors,
    publicZuploEnvironmentVariables: envZuplo
      ? {
          // biome-ignore lint/style/useNamingConvention: External API property
          ZUPLO_ACCOUNT_NAME: envZuplo.ZUPLO_ACCOUNT_NAME,
          // biome-ignore lint/style/useNamingConvention: External API property
          ZUPLO_PROJECT_NAME: envZuplo.ZUPLO_PROJECT_NAME,
          // biome-ignore lint/style/useNamingConvention: External API property
          ZUPLO_ENVIRONMENT_TYPE: envZuplo.ZUPLO_ENVIRONMENT_TYPE,
        }
      : // Leave this as undefined to simulate the old behavior
        undefined,
    logger,
    handleRuntimeStdio,
    onReload: () => {
      if (firstLoad) {
        firstLoad = false;
      } else {
        printDiagnosticsToConsole("Code changed. Server reloaded...");
      }
    },
  });

  let editor: LocalEditorServer;

  if (argv["start-editor"]) {
    editor = new LocalEditorServer({
      sourceDirectory,
      deploymentUrl: `http://localhost:${zupPort}`,
      port: argv.editorPort,
      logger,
    });
    editor.start().catch((err) => logger.error(err));
  }

  let docsProcess: ExecaChildProcess | undefined;

  if (startDocs) {
    const npxExecutable = process.platform === "win32" ? "npx.cmd" : "npx";
    docsProcess = execa(
      npxExecutable,
      ["zudoku", "dev", "--zuplo", "--port", String(docsPort)],
      {
        cwd: docsDirectory,
        env: {
          // biome-ignore lint/style/noProcessEnv: Pass through environment
          ...process.env,
          // Ensure that the Zudoku server pipes through colored output even if it's
          // not sending it through a TTY and instead is using the prefixed transform
          // https://force-color.org/
          // biome-ignore lint/style/useNamingConvention: Environment variable naming
          FORCE_COLOR: "1",
          // biome-ignore lint/style/useNamingConvention: Environment variable naming
          ZUPLO_SERVER_URL: `http://localhost:${zupPort}`,
        },
      }
    );
    const docsStdoutTransform = createPrefixedTransform({
      name: "docs",
      color: chalk.magenta,
    });
    const docsStderrTransform = createPrefixedTransform({
      name: "docs",
      color: chalk.magenta,
    });
    docsProcess.stdout?.pipe(docsStdoutTransform).pipe(process.stdout);
    docsProcess.stderr?.pipe(docsStderrTransform).pipe(process.stderr);
  }

  printDiagnosticsToConsole("Started local development setup");
  printDiagnosticsToConsole("Ctrl+C to exit");
  printDiagnosticsToConsole("");
  printDiagnosticsToConsole(`🚀 Zuplo Gateway: http://localhost:${zupPort}`);
  if (argv["start-editor"]) {
    printDiagnosticsToConsole(
      `📘 Route Designer: http://localhost:${argv.editorPort}`
    );
  }
  if (startDocs) {
    printDiagnosticsToConsole(`📄 Docs Server: http://localhost:${docsPort}`);
  }
  if (loadedEnvFiles.length > 0) {
    printDiagnosticsToConsole(
      `⚙️  Loaded env files: \n    - ${loadedEnvFiles.join(" \n    - ")}`
    );
  }
  printDiagnosticsToConsole("");
  printDiagnosticsToConsole("");

  return new Promise<void>((resolve) => {
    async function exit() {
      process.off("SIGTERM", exit);
      process.off("SIGINT", exit);

      printDiagnosticsToConsole("");
      printDiagnosticsToConsole("Stopping local development server...");

      if (argv["start-editor"]) {
        await editor.close();
      }
      if (docsProcess) {
        docsProcess.kill("SIGTERM");
      }

      resolve();
    }

    // Handle user-initiated shutdown
    process.on("SIGTERM", exit);
    process.on("SIGINT", exit);

    // Handle child process exiting and cleanup
    if (docsProcess) {
      docsProcess.on("close", (code, signal) => {
        if (signal === "SIGTERM" || signal === "SIGINT") {
          return;
        }

        if (code !== 0) {
          printWarningToConsole(`Docs server exited with code ${code}.`);
        }
      });

      docsProcess.on("error", (err) => {
        printWarningToConsole(`Failed to start docs server: ${err.message}`);
      });
    }
  });
}
"]}
